const crypto = require('crypto');
const html = $input.item.json.data || $input.item.json.body || '';
const cleanHtml = html.replace(/\s+/g, ' ').replace(/<!--.*?-->/g, '').trim();
const newHash = crypto.createHash('sha256').update(cleanHtml).digest('hex');
const oldHash = $input.item.json.content_hash || '';
const hasChanged = oldHash && newHash !== oldHash;

return {
  json: {
    id: $input.item.json.id,
    sourceId: $input.item.json.source_id,
    title: $input.item.json.title,
    url: $input.item.json.url,
    targetPage: $input.item.json.target_page,
    targetSection: $input.item.json.target_section,
    priority: $input.item.json.priority,
    oldHash,
    newHash,
    hasChanged,
    content: cleanHtml.substring(0, 5000)
  }
};

// NetworkChuck-style UUID generation
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c == 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

return {
  json: {
    sessionId: uuid,
    sourceId: $input.item.json.sourceId,
    title: $input.item.json.title,
    url: $input.item.json.url,
    targetPage: $input.item.json.targetPage,
    targetSection: $input.item.json.targetSection,
    priority: $input.item.json.priority,
    oldHash: $input.item.json.oldHash,
    newHash: $input.item.json.newHash,
    content: $input.item.json.content
  }
};

