parameters.functionCode:
// Parse OpenCode response (NetworkChuck style)
const output = $input.item.json.stdout || $input.item.json.stderr || '';

// Extract JSON from output
const jsonMatch = output.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No JSON found in OpenCode response');
}

const analysis = JSON.parse(jsonMatch[0]);

return {
  json: {
    sessionId: $('Generate Session ID').item.json.sessionId,
    sourceId: $('Generate Session ID').item.json.sourceId,
    title: $('Generate Session ID').item.json.title,
    url: $('Generate Session ID').item.json.url,
    targetPage: $('Generate Session ID').item.json.targetPage,
    targetSection: $('Generate Session ID').item.json.targetSection,
    priority: $('Generate Session ID').item.json.priority,
    newHash: $('Generate Session ID').item.json.newHash,
    analysis: analysis,
    summary: analysis.summary,
    severity: analysis.severity,
    affectedPages: JSON.stringify(analysis.affected_pages),
    impactAssessment: analysis.impact_assessment,
    updatedHtml: analysis.updated_html,
    recommendations: analysis.recommendations
  }
};

